import{_ as a,c as n,o as s,ag as t}from"./chunks/framework.IQH0tUiJ.js";const u=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md"}'),o={name:"guide/index.md"};function i(r,e,l,p,d,c){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="what-is-webui" tabindex="-1">What is WebUI? <a class="header-anchor" href="#what-is-webui" aria-label="Permalink to &quot;What is WebUI?&quot;">​</a></h2><p>WebUI is a server-side rendering framework that compiles HTML templates into a binary protocol at build time. At runtime, your backend simply applies state data to the pre-compiled protocol and gets rendered HTML back — no template parsing, no JavaScript runtime, minimal computation.</p><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>Traditional server-side rendering re-parses and re-evaluates templates on every request. JavaScript-based SSR frameworks require a Node.js runtime on the server. Both approaches add latency and complexity that scales poorly.</p><h2 id="how-webui-works" tabindex="-1">How WebUI Works <a class="header-anchor" href="#how-webui-works" aria-label="Permalink to &quot;How WebUI Works&quot;">​</a></h2><p>WebUI splits the work into two phases:</p><ol><li><p><strong>Build time</strong> — The CLI parses your HTML templates, discovers web components, evaluates static content, and compiles everything into a compact Protocol Buffer binary. Static and dynamic content are separated. This happens once.</p></li><li><p><strong>Runtime</strong> — Your backend handler loads the pre-compiled protocol, receives JSON state data, and produces rendered HTML. No parsing, no AST walking, no expression compilation — just fill in the blanks.</p></li></ol><p>The result: rendering is fast, predictable, and language-agnostic.</p><h2 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h2><ul><li><p><strong>Protocol Buffer binary</strong> — Templates compile to a compact binary format. The handler reads fragments sequentially — static fragments are emitted as-is, dynamic fragments are resolved from state.</p></li><li><p><strong>Language agnostic</strong> — Native handlers for Rust, Node/Bun/Deno, C#, Python, and Go. Any other language can use the C FFI bindings.</p></li><li><p><strong>Web Components</strong> — Templates are standard HTML with native web components and Shadow DOM. No proprietary syntax beyond a few template directives (<code>&lt;if&gt;</code>, <code>&lt;for&gt;</code>, <code>{{}}</code>).</p></li><li><p><strong>Routing</strong> — The <code>&lt;route&gt;</code> directive defines URL-to-component mappings. The server renders the matched route on first load; the optional <a href="/guide/concepts/routing.html"><code>@microsoft/webui-router</code></a> package adds client-side navigation with lazy loading.</p></li><li><p><strong>Server-side expressions</strong> — Conditionals and expressions are evaluated on the server. Template logic doesn&#39;t leak into the browser.</p></li><li><p><strong>Plugin system</strong> — Parser and handler plugins for hydration, adding reactivity to interactive islands, custom directives, and framework-specific behavior.</p></li></ul><h2 id="quick-overview" tabindex="-1">Quick Overview <a class="header-anchor" href="#quick-overview" aria-label="Permalink to &quot;Quick Overview&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────┐    ┌───────────────┐    ┌───────────────┐</span></span>
<span class="line"><span>│  HTML + CSS  │───▶│  webui build  │───▶│ .webui binary │</span></span>
<span class="line"><span>│  templates   │    │  (build time) │    │  (protocol)   │</span></span>
<span class="line"><span>└──────────────┘    └───────────────┘    └───────┬───────┘</span></span>
<span class="line"><span>                                                 │</span></span>
<span class="line"><span>                    ┌───────────────┐            │</span></span>
<span class="line"><span>                    │  JSON state   │────────────┤</span></span>
<span class="line"><span>                    │  (runtime)    │            │</span></span>
<span class="line"><span>                    └───────────────┘            ▼</span></span>
<span class="line"><span>                                         ┌───────────────┐</span></span>
<span class="line"><span>                                         │    handler    │</span></span>
<span class="line"><span>                                         │   (any lang   │</span></span>
<span class="line"><span>                                         └───────┬───────┘</span></span>
<span class="line"><span>                                                 │</span></span>
<span class="line"><span>                                                 ▼</span></span>
<span class="line"><span>                                         ┌───────────────┐</span></span>
<span class="line"><span>                                         │ rendered HTML │</span></span>
<span class="line"><span>                                         └───────────────┘</span></span></code></pre></div><p>Ready to try it? Start with the <a href="/playground/">Playground</a> to experiment in the browser, then follow the <a href="./installation.html">installation guide</a> or the <a href="/tutorials/hello-world.html">Hello World tutorial</a> to build locally.</p>`,14)])])}const m=a(o,[["render",i]]);export{u as __pageData,m as default};
